css:
/* --- 字体 --- */
@import url("https://fontsapi.zeoseven.com/515/main/result.css");

:root {
  --main-font: "LXGW Neo XiHei Plus", sans-serif;
  --base-dark-brown: rgb(80, 55, 40); /* 主要不透明棕色 - 深橡木色 */
  --panel-bg-color: rgba(100, 70, 50, 0.95); /* 其他面板的半透明中等木色 */
  --input-bg-color: rgb(110, 75, 55); /* 输入框背景 - 较浅木色 */
  --button-bg-color: rgb(70, 50, 35); /* 按钮背景 - 深木色 */
  --button-hover-bg-color: rgb(90, 70, 50); /* 按钮悬停背景 */
  --reasoning-bg-color: rgba(90, 70, 55, 0.92); /* 推理链背景 - 略微不同的木色 */
  --code-bg-color: rgba(40, 35, 30, 0.85);
  --blockquote-bg-color: rgba(20, 15, 10, 0.92); /* Blockquote 更深背景色 */
  --border-color: rgba(160, 82, 45, 0.9);
  --text-color: rgba(245, 245, 245, 0.9);
  --text-secondary-color: rgba(200, 200, 200, 0.8);
  --text-accent-color: rgb(214, 154, 4);
  --title-accent-bright: hsl(45, 100%, 60%); /* 更亮的标题用强调金色 */
  --bright-yellow-quote: hsl(55, 100%, 70%); /* 用于 <q> 标签的亮黄色 */
  --button-icon-color: var(--text-accent-color);
  --generic-radius: 4px;
  --box-shadow-subtle: 0 2px 5px rgba(0, 0, 0, 0.3);
  --noble-border: 1px solid var(--border-color);
  --card-base-bg: rgb(70, 45, 30); /* 卡片深棕背景 */
  --card-text-on-dark-bg: rgba(230, 220, 210, 0.9); /* 深色卡片上的文字颜色 (如信息、时间戳) */
  --button-size: 32px;
  --icon-actual-size: 45px;/* 按钮大小 */

  --accent-color-purple-base: rgb(226, 226, 226);
  --accent-color-gold: var(--text-accent-color);
  --card-name-text-color: var(--text-accent-color);
  --card-icon-size: 35px; /* 新增卡片图标大小变量 */
  --mainFontSize: 16px; /* Add this for compatibility with example if needed, or adjust specific font sizes */
  --avatar-base-height: 48px; /* From example, if needed for specific calcs */
  --topBarBlockSize: 50px; /* Example value, adjust if using iPad specific styles */
  --sheldWidth: 90%; /* Example value, adjust if using iPad specific styles */
}

body {
  font-family: var(--main-font);
  color: var(--text-color);
  background-color: var(--base-dark-brown); /* Fallback */
  background-image: url('https://files.catbox.moe/geqc9d.png');
  background-size: cover;
  background-position: center center;
  background-attachment: fixed;
}

/* --- 主要布局元素 --- */
#chat {
  background-color: var(--panel-bg-color); /* 应用带透明度的背景 */
  border-radius: var(--generic-radius);
  padding: 10px;
  box-shadow: var(--box-shadow-subtle);
  border: var(--noble-border);
  margin-top: 10px;
}

#top-bar {
  background-color: var(--base-dark-brown) !important; /* 改为不透明深棕色 */
  border-radius: var(--generic-radius);
  border: var(--noble-border);
  margin-bottom: 10px;
  padding: 5px;
  box-shadow: var(--box-shadow-subtle);
}

/* 新增：确保顶部图标区域的背景也是统一的深褐色 */
#top-settings-holder {
  background-color: var(--base-dark-brown) !important;
  background-image: none !important; /* 移除可能的渐变背景 */
  padding: 0 5px; /* 根据需要调整内边距 */
}

#send_form {
  background-color: var(--base-dark-brown) !important;
  border-radius: var(--generic-radius);
  border-style: solid;
  border-width: 2px;
  border-color: var(--accent-color-gold);
  padding: 8px;
  box-shadow: var(--box-shadow-subtle), 
              0 0 7px var(--accent-color-gold),
              0 0 12px rgba(214, 154, 4, 0.5);
  display: flex;
  align-items: center;
  position: relative; /* Needed if QR bar is absolutely positioned relative to it */
}

#send_textarea {
  background-color: var(--input-bg-color) !important;
  border: 1px solid var(--border-color) !important;
  border-radius: var(--generic-radius);
  color: var(--text-color);
  padding: 8px;
}

/* --- 侧边栏 & 菜单 --- */
#left-nav-panel,
#right-nav-panel,
.drawer-content,
.popup,
#options,
#extensionsMenu {
  background-color: var(--panel-bg-color) !important; /* 应用带透明度的背景 */
  border-radius: var(--generic-radius);
  border: var(--noble-border);
  box-shadow: var(--box-shadow-subtle);
  color: var(--text-color);
  padding: 10px;
}

.drawer-content h3,
.popup h3,
#user-settings-block h4,
.standoutHeader {
  color: var(--text-accent-color);
  border-bottom: 1px solid var(--border-color);
  padding-bottom: 5px;
  margin-bottom: 10px;
}

/* --- 聊天气泡 --- */
.mes {
  background-color: transparent;
  border: none !important;
  margin-bottom: 15px;
  padding: 0;
}

/* AI 消息卡片化布局 */
.mes:not([is_user="true"]) {
    position: relative; /* 为内部绝对定位元素提供基准 */
    padding-top: 90px; /* 为顶部的卡片预留空间, 根据实际卡片高度调整 */
    margin-bottom: 25px; /* 增加一点底部间距 */
}

.mes:not([is_user="true"]) .mes_block {
  /* mes_block 现在是卡片下方的实际消息内容区 */
  background-color: rgb(60, 35, 20); /* 再次调深AI消息背景 */
  border: var(--noble-border);
  border-radius: var(--generic-radius);
  padding: 12px;
  box-shadow: var(--box-shadow-subtle);
  margin-top: 0; /* 因为父级.mes已经有了padding-top */
}

/* AI 消息卡片主体 (原 .ch_name 区域改造) */
.mes:not([is_user="true"]) .ch_name {
  position: absolute;
  left: 1.5px;
  top: 0;
  padding: 10px calc(var(--card-icon-size) + 15px) 10px 88px;
  min-width: 250px;
  max-width: calc(100% - 3px);
  min-height: 80px;
  height: auto;
  box-sizing: border-box;
  z-index: 1;
  white-space: nowrap;

  background-color: var(--card-base-bg);
  /* Subtle Paper/Linen Texture REMOVED */

  border-radius: var(--generic-radius);
  border: 1.4px solid var(--accent-color-gold);
  box-shadow: 0px 4px 10px 0px rgba(0,0,0,0.3);

  font-family: var(--main-font); /* 使用主题字体 */
  font-size: 18px; /* 名字字体大小 */
  font-weight: 600;
  text-shadow: 1px 1px 2px hsla(35, 20%, 50%, 0.3);
  color: var(--card-name-text-color) !important; 
  overflow: hidden; /* Keep this to prevent icon overflow if not perfectly sized */
}

.mes:not([is_user="true"]) .ch_name::after { /* 新卡片图标 for AI */
    content: "";
    position: absolute;
    right: 10px; /* 图标在卡片右侧 */
    top: 50%;
    transform: translateY(-50%);
    width: var(--card-icon-size);
    height: var(--card-icon-size);
    background-image: url('https://files.catbox.moe/8r8vkf.png');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    z-index: 3; /* Ensure it's above card background */
}

/* 当AI消息处于编辑状态时，确保卡片背景 */
.mes.editing:not([is_user="true"]) .ch_name {
    min-height: 80px; /* 再次强调最小高度 */
}

/* AI 头像定位到卡片上 */
.mes:not([is_user="true"]) .avatar {
    position: absolute;
    top: 12px; /* 头像在卡片上的垂直位置 */
    left: 15px; /* 头像在卡片上的水平位置 */
    z-index: 2;
    width: 60px; /* 固定头像区域大小 */
    height: 60px;
    background-color: transparent; /* Or a subtle bg for the avatar area if needed */
    background-size: cover;
    background-position: center;
    background-repeat: repeat;
    border-radius: var(--generic-radius) !important;
    border: 2px solid var(--accent-color-gold);
    box-shadow: 0px 2px 4px rgba(0,0,0,0.2);
}
.mes:not([is_user="true"]) .avatar img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    border-radius: calc(var(--generic-radius) - 2px); /* 内部图片圆角略小 */
}

/* AI 卡片上的信息文本 (时间戳, ID, Token) */
.mes:not([is_user="true"]) .timestamp,
.mes:not([is_user="true"]) .mesIDDisplay,
.mes:not([is_user="true"]) .tokenCounterDisplay,
.mes:not([is_user="true"]) .mes_timer /* 假设 .mes_timer 也存在于AI消息 */
{
  position: absolute;
  z-index: 2; /* 在卡片背景之上 */
  font-family: var(--main-font);
  color: var(--card-text-on-dark-bg); /* Darker text for readability on light paper background */
  opacity: 0.9;
  font-size: 11px;
  text-shadow: none;
  left: 90px; /* 名字右侧开始 */
}

.mes:not([is_user="true"]) .timestamp {
  top: 35px; /* 时间戳位置 */
  border-bottom: 1px dashed var(--card-text-on-dark-bg);
  padding-bottom: 1px;
}

.mes:not([is_user="true"]) .mesIDDisplay {
  top: 55px; /* ID位置 */
  width: auto; /* 根据内容自适应 */
  padding-right: 5px;
}

.mes:not([is_user="true"]) .tokenCounterDisplay {
  top: 55px; /* Token 位置 */
  left: 130px; /* 大约在ID之后，根据实际效果调整 */
  width: auto;
}

/* AI 卡片上的模型图标 (如果存在 .icon-svg) */
.mes:not([is_user="true"]) .icon-svg {
    position: absolute;
    right: calc(var(--card-icon-size) + 20px); /* Position next to the new card icon */
    top: 50%;
    transform: translateY(-50%);
    width: 16px;
    height: 16px;
    color: var(--accent-color-gold);
    z-index: 3;
    filter: drop-shadow(0.5px 0.5px 0.5px rgba(255, 255, 255, 0.3))
            drop-shadow(-0.5px -0.5px 0.5px rgba(0, 0, 0, 0.2));
}

.mes .ch_name {
  color: var(--text-accent-color);
  font-weight: bold;
  margin-bottom: 5px;
}

.mes .mes_text {
  color: var(--text-color);
  line-height: 1.6;
}


.mes_text strong {
    color: var(--text-accent-color);  /* 使用更新后的强调色 */
    text-shadow: 0 0 3px rgba(214, 154, 4, 0.3); /* 轻微光晕 */
}

/* 单反引号代码块 */
.mes_text code {
    background-color: var(--code-bg-color) !important;
    color: var(--text-accent-color) !important;
    padding: 0.3em 0.5em; /* 调整内边距 */
    border-radius: 3px;
    font-size: 0.9em;
    border: 1px solid rgba(210, 180, 140,0.3); /* 淡金色边框 */
    line-height: 1.8;  /* 行距 */ 
}

/* 三反引号代码块 */
.mes_text pre {
    background-color: rgba(0,0,0,0.3); /* 比面板稍暗一点, 增加对比度 */
    padding: 0.8em 1em; 
    border-radius: var(--generic-radius);
    font-family: inherit;    
    font-size: 0.95em;
    letter-spacing: 0.3px;
    overflow-x: auto;
    white-space: pre-wrap;
    word-break: break-word;
    border-left: 3px solid var(--text-accent-color); /* 边框改为强调色 */
    position: relative;
    box-shadow: 3px 3px 6px rgba(0,0,0,0.3); /* 增强阴影 */
    margin: 10px 0; /* 增加外边距 */
}

.mes_text pre code {
    padding: 0 !important; 
    background-color: transparent !important;
    color: var(--text-color) !important; /* 代码块内文字颜色 */
    line-height: 1.5;
    border-radius: 0; 
    border: none !important;
    font-size: inherit !important;
}

/* 代码块复制按钮 */
.mes_text pre .code-copy {
    display: none !important; /* 移除复制按钮 */
    opacity: 0.8;
    transition: filter 0.2s ease-in-out;
    color: var(--accent-color-gold);
    background-color: rgba(0,0,0,0.3);
    border-radius: 3px;
    padding: 2px 4px;
}
.mes_text pre .code-copy:hover {
  filter: brightness(150%);
}

/* 引用文本 */
.mes_text blockquote {
    border-left: 5px solid var(--text-accent-color); /* 强调边框 */
    border-radius: var(--generic-radius); 
    box-shadow: 2px 2px 4px rgba(0,0,0,0.2);
    background-color: var(--blockquote-bg-color); /* 使用更深的背景以增强对比度 */
    padding: 0.7em 1.2em; /* 调整内边距 */
    margin: 10px 0; /* 增加外边距 */
    color: var(--text-accent-color); /* 修改为金黄色 */
}

/* --- 新增：q 标签 (双引号内文本) 样式 --- */
.mes_text q {
  color: var(--bright-yellow-quote);
  /* CSS无法直接添加实际的 " 引号，浏览器通常会为 <q> 自动添加，或平台会处理 */
}

/* --- 新增：链接样式 --- */
.mes_text a {
  color: var(--text-accent-color);
  text-decoration: none;
  text-shadow: 0 0 5px var(--text-accent-color), 0 0 8px rgba(214, 154, 4, 0.7);
  transition: color 0.2s ease, text-shadow 0.2s ease;
}

.mes_text a:hover {
  color: hsl(40, 100%, 70%); /* 悬停时更亮的金色 */
  text-decoration: underline;
  text-shadow: 0 0 7px hsl(40, 100%, 70%), 0 0 12px rgba(214, 154, 4, 0.8);
}

/* --- 新增：删除线样式 --- */
.mes_text del,
.mes_text s {
  color: rgba(200, 200, 200, 0.7); /* 较浅的文本颜色 */
  text-decoration: line-through;
  text-decoration-color: hsl(50, 100%, 70%); /* 更亮的删除线颜色 */
  text-decoration-thickness: 1px;
}

/* --- 新增：斜体 (em, i) 文本样式 --- */
.mes_text em,
.mes_text i {
  color: var(--text-accent-color); /* 使用主题强调色以确保可见性 */
  font-style: italic; /* 确保它们确实是斜体 */
  /* text-shadow: 0 0 1px rgba(214, 154, 4, 0.2); /* 可选：轻微光晕增加辨识度 */
}

/* --- 新增：Details/Summary 标签样式 --- */
.mes_text details {
  margin: 10px 0;
  border: 1px solid var(--border-color);
  border-radius: var(--generic-radius);
  background-color: rgba(0,0,0,0.1);
  overflow: hidden; /* 确保圆角效果 */
}

.mes_text summary {
  padding: 10px 15px;
  cursor: pointer;
  font-weight: bold;
  color: var(--text-accent-color);
  background-color: var(--input-bg-color); /* 使用输入框背景作为基色 */
  list-style-position: inside; /* 尝试将箭头放在内部 */
  border-bottom: 1px solid transparent; /* 初始无下边框 */
  transition: background-color 0.2s ease;
}

.mes_text summary:hover {
  background-color: var(--button-hover-bg-color); /* 悬停时使用按钮悬停色 */
}

.mes_text details[open] summary {
  background-color: var(--base-dark-brown); /* 打开时使用更深的基色 */
  border-bottom: 1px solid var(--border-color); /* 打开时显示下边框 */
  margin-bottom: 5px;
}

.mes_text details > div, /* 如果 details 直接包含内容 */
.mes_text details > p /* 如果 details 内是p标签 */
{ 
  padding: 10px 15px;
  background-color: rgba(0,0,0,0.05); /* 内容区域的细微背景 */
}

/* --- 推理链 --- */
.mes_reasoning_header {
    background-color: var(--reasoning-bg-color) !important;
    border: 1px solid var(--accent-color-gold) !important;
    border-radius: var(--generic-radius);
    padding: 0.6em 1em 0.6em 2.5em; /* 调整内边距，为图标留空间 */
    margin-bottom: 8px;
    color: var(--text-color);
    font-family: "LXGW Neo XiHei Plus", sans-serif;
    font-size: calc(var(--main-font-size, 1em) * 0.85);
    letter-spacing: 0.5px;
    position: relative; 
    transition: border-color 0.3s ease, background-color 0.3s ease; 
    cursor: pointer;
}

.mes_reasoning_header::before { /* 更新为书本图标 📔 */
  content: "📔"; /* 直接使用 emoji */
  position: absolute;
  left: 0.7em; 
  top: 50%;
  transform: translateY(-50%); 
  font-size: 1.3em; /* 调整 emoji 大小 */
  color: var(--text-accent-color); /* 使用强调色 */
}


.mes_reasoning_header:hover {
  border-color: var(--text-accent-color) !important;
  background-color: rgba(90, 70, 60, 0.95) !important; /* 悬停时更深一点 */
}

.mes_reasoning_details,
.mes_reasoning
{
    background-color: rgba(0,0,0,0.05);
    padding: 8px;
    border-left: 2px solid var(--border-color);
    margin-left: 0px; /* 调整对齐 */
    border-radius: 0 0 var(--generic-radius) var(--generic-radius);
}

/* --- 按钮 --- */
.menu_button,
input[type='button'],
button {
  background-image: var(--shared-bg-image); /* 应用共享背景 */
  background-color: var(--button-bg-color) !important; /* 底色，纹理可能半透明 */
  background-repeat: repeat;
  background-blend-mode: multiply; /* 尝试混合模式 */
  border: 1px solid var(--border-color) !important;
  color: var(--button-icon-color) !important;
  border-radius: var(--generic-radius);
  padding: 5px 10px;
  transition: background-color 0.2s ease, border-color 0.2s ease, transform 0.1s ease;
  box-shadow: inset 0 1px 1px rgba(0,0,0,0.2), 0 1px 2px rgba(0,0,0,0.3);
  filter: none !important;
  min-width: var(--button-size);
  min-height: var(--button-size);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  text-shadow: 1px 1px 1px rgba(0,0,0,0.2);
}

.menu_button:hover,
input[type='button']:hover,
button:hover {
  background-color: var(--button-hover-bg-color) !important;
  border-color: var(--text-accent-color) !important;
  transform: translateY(-1px);
}

.menu_button:active,
input[type='button']:active,
button:active {
  transform: translateY(0px);
  box-shadow: inset 0 2px 3px rgba(0,0,0,0.3);
}

/* --- 特定按钮图标 --- */
#extensionsMenuButton /* 打开扩展按钮 */ {
  background-image: url('https://files.catbox.moe/vn0jtm.png') !important;
  background-size: calc(var(--icon-actual-size) * 0.85) calc(var(--icon-actual-size) * 0.85) !important;
  background-position: center center !important;
  background-repeat: no-repeat !important;
  background-color: transparent !important;
  border: none !important;
  color: transparent !important; /* Hide original icon/text */
  font-size: 0 !important; /* Hide original icon/text */
  width: var(--button-size) !important;
  height: var(--button-size) !important;
  padding: 0 !important;
  margin-right: 3px; /* Spacing */
  box-shadow: none !important;
}

#options_button /* 扩展旁的按钮 (三条横线) */ {
  background-image: url('https://files.catbox.moe/vfsuf7.png') !important;
  background-size: calc(var(--icon-actual-size) * 0.85) calc(var(--icon-actual-size) * 0.85) !important;
  background-position: center center !important;
  background-repeat: no-repeat !important;
  background-color: transparent !important;
  border: none !important;
  color: transparent !important; /* Hide original icon/text */
  font-size: 0 !important; /* Hide original icon/text */
  width: var(--button-size) !important;
  height: var(--button-size) !important;
  padding: 0 !important;
  margin-left: 3px; /* Spacing */
  box-shadow: none !important;
}

#send_but /* 发送按钮 */ {
  background-image: url('https://files.catbox.moe/sk3979.png') !important;
  background-size: calc(var(--icon-actual-size) * 0.85) calc(var(--icon-actual-size) * 0.85) !important;
  background-position: center center !important;
  background-repeat: no-repeat !important;
  background-color: transparent !important;
  border: none !important;
  color: transparent !important;
  font-size: 0 !important; /* 尝试隐藏可能的原生按钮文本/图标 */
  width: var(--button-size) !important;
  height: var(--button-size) !important;
  padding: 0 !important;
  margin: 0 5px;
  filter: none !important;
  box-shadow: none !important;
}

/* --- 其他控件 --- */
select,
input[type='text'],
input[type='number'],
textarea {
  background-color: var(--input-bg-color) !important; /* 输入控件背景保持不透明或按需调整 */
  border: 1px solid var(--border-color) !important;
  color: var(--text-color) !important;
  border-radius: var(--generic-radius);
  padding: 4px 6px;
}

select:focus,
input:focus,
textarea:focus {
  outline: none;
  border-color: var(--text-accent-color) !important;
  box-shadow: 0 0 5px rgba(210, 180, 140, 0.5);
}

/* --- 复选框样式 (Checkbox) --- */
input[type='checkbox'] {
    appearance: none;
    -webkit-appearance: none;
    background-color: var(--input-bg-color); /* Base background, can be transparent if border is enough */
    border: 2px solid var(--border-color);
    border-radius: var(--generic-radius);
    width: 1.1em;
    height: 1.1em;
    display: inline-block;
    position: relative;
    vertical-align: middle; /* Align with text */
    cursor: pointer;
    transition: background-color 0.2s ease, border-color 0.2s ease;
}

input[type='checkbox']::before { /* Remove any default checkmark if present via ::before */
    content: none;
}

input[type='checkbox']:checked {
    background-image: url('https://files.catbox.moe/9n84au.png');
    background-size: 80% 80%; /* Adjust icon size within checkbox */
    background-position: center;
    background-repeat: no-repeat;
    border-color: var(--accent-color-gold); /* Highlight border when checked */
    /* Optionally, add a subtle animation like the example */
    animation: checkAnimLib 0.2s ease-in;
}

@keyframes checkAnimLib {
    from { background-size: 0% 0%; opacity: 0; }
    to { background-size: 80% 80%; opacity: 1; }
}

input[type='checkbox']:hover {
    border-color: var(--accent-color-gold);
}

/* --- 滑块及滑块输入框样式 (Range Input) --- */
/* 滑块输入框样式 (neo-range-input, if you use this class structure) */
.neo-range-input, .range-block-counter input {
    background-color: var(--input-bg-color);
    border: 1px solid var(--border-color);
    border-radius: var(--generic-radius);
    padding: 4px 6px;
}

/* 滑块滑动条样式 */
.neo-range-slider, input[type="range"] {
    width: 100%;
    height: 8px;
    cursor: pointer;
    background: var(--input-bg-color);
    border-radius: var(--generic-radius);
    border: 1px solid var(--border-color);
}

/* 滑块图标 (Thumb) */
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none; /* Important to override default on Chrome/Safari */
    appearance: none;
    width: 28px; /* Adjust width of thumb */
    height: 28px; /* Adjust height of thumb */
    background: url('https://files.catbox.moe/ytrth0.png') no-repeat center center;
    background-size: contain; /* Ensure icon fits */
    border: none; /* Remove default border */
    border-radius: 0; /* Or 50% for circle if icon is circular */
    box-shadow: none;
    cursor: pointer;
    margin-top: -10px; /* Adjust vertical centering if track is thinner than thumb */
    transition: transform 0.1s ease;
}

input[type="range"]::-moz-range-thumb {
    width: 28px;
    height: 28px;
    background: url('https://files.catbox.moe/ytrth0.png') no-repeat center center;
    background-size: contain;
    border: none;
    border-radius: 0;
    box-shadow: none;
    cursor: pointer;
}

input[type="range"]::-webkit-slider-thumb:hover,
input[type="range"]::-moz-range-thumb:hover {
    transform: scale(1.1); /* Slight zoom on hover */
}

input[type="range"]:focus::-webkit-slider-thumb,
input[type="range"]:focus::-moz-range-thumb {
    /* Optional: add focus style to thumb */
    /* box-shadow: 0 0 0 3px rgba(214, 154, 4, 0.3); */
}

/* 用户消息卡片化布局 */
.mes[is_user="true"] {
    position: relative;
    padding-top: 90px; /* 为顶部的卡片预留空间 */
    margin-bottom: 25px;
    margin-top: 10px; /* 与AI消息卡片区分，或统一 */
}

.mes[is_user="true"] .mes_block {
  /* 用户消息的实际内容区 */
  background-color: rgb(60, 35, 20); /* 再次调深用户消息背景 */
  border: var(--noble-border);
  border-radius: var(--generic-radius);
  padding: 12px;
  box-shadow: var(--box-shadow-subtle);
  margin-top: 0;
}

/* 用户消息卡片主体 */
.mes[is_user="true"] .ch_name /* 假设用户消息也有 .ch_name 显示用户名 */
{
  position: absolute;
  right: 1.5px; /* 用户卡片靠右 */
  top: 0;
  padding: 10px 88px 10px calc(var(--card-icon-size) + 15px); /* 左侧padding为图标留空间 */
  min-width: 250px;
  max-width: calc(100% - 3px);
  min-height: 80px;
  height: auto;
  box-sizing: border-box;
  z-index: 1;
  white-space: nowrap;
  text-align: right; /* 用户名靠右 */

  background-color: var(--card-base-bg);
  /* Subtle Paper/Linen Texture REMOVED */

  border-radius: var(--generic-radius);
  border: 1.4px solid var(--accent-color-gold);
  box-shadow: 0px 4px 10px 0px rgba(0,0,0,0.3);

  font-family: var(--main-font);
  font-size: 18px;
  font-weight: 600;
  text-shadow: 1px 1px 2px hsla(35, 20%, 50%, 0.3);
  color: var(--card-name-text-color) !important; 
  overflow: hidden;
}

.mes[is_user="true"] .ch_name::after { /* 新卡片图标 for User */
    content: "";
    position: absolute;
    left: 10px; /* 图标在卡片左侧 */
    top: 50%;
    transform: translateY(-50%);
    width: var(--card-icon-size);
    height: var(--card-icon-size);
    background-image: url('https://files.catbox.moe/8r8vkf.png');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    z-index: 3;
}

/* 用户头像定位到卡片上 */
.mes[is_user="true"] .avatar {
    position: absolute;
    top: 12px;
    right: 15px; /* 用户头像在卡片右侧 */
    z-index: 2;
    width: 60px;
    height: 60px;
    background-color: transparent; /* Or a subtle bg for the avatar area if needed */
    background-size: cover;
    background-position: center;
    background-repeat: repeat; 
    border-radius: var(--generic-radius) !important;
    border: 2px solid var(--accent-color-gold);
    box-shadow: 0px 2px 4px rgba(0,0,0,0.2);
}
.mes[is_user="true"] .avatar img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    border-radius: calc(var(--generic-radius) - 2px);
