/* --- 自动隐藏快速回复 --- */
/* 假设快速回复栏的ID是 #qr--bar 或类是 .quick-reply-container */
/* 如果实际ID/类不同，请替换下面的 #qr--bar */
#qr--bar {
  opacity: 0;
  visibility: hidden; /* 明确设置为隐藏 */
  transform: translateY(15px);
  max-height: 0;
  overflow: hidden;
  pointer-events: none; /* 阻止隐藏时的交互 */
  transition: 
    opacity 0.15s ease-out,    /* 透明度快速消失 */
    transform 0.15s ease-out,  /* 位置快速变化 */
    max-height 0.2s ease-out,  /* 高度塌陷 */
    visibility 0s linear 0.15s;/* 在透明度动画结束后应用 hidden */
}

#send_form:focus-within #qr--bar,
#send_textarea:focus ~ #qr--bar
{
  opacity: 1;
  visibility: visible; /* 明确设置为可见 */
  transform: translateY(0);
  max-height: 200px; /* Adjust to fit your quick reply content height */
  pointer-events: auto; /* 允许显示时的交互 */
  transition: 
    opacity 0.2s ease-in,
    transform 0.2s ease-in,
    max-height 0.2s ease-in,
    visibility 0s linear 0s; /* 立即应用 visible */
}

